import React from "react";
import { useParams } from "react-router-dom";
import { recipes } from "./recipesData";

const RecipeDetail = () => {
  const { id } = useParams();

  // Find the recipe by ID
  const recipe = recipes.find((recipe) => recipe._id.$oid === id);

  if (!recipe) {
    return (
      <div className="container">
        <h1>Recipe Not Found</h1>
        <p>Sorry, the recipe you're looking for doesn't exist.</p>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Recipe Header */}
      <div className="bg-white rounded-lg shadow-lg overflow-hidden">
        <img
          src={recipe.image}
          alt={recipe.title}
          className="w-full h-64 object-cover"
        />

        <div className="p-6">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            {recipe.title}
          </h1>
          <p className="text-gray-600 mb-4">{recipe.description}</p>

          {/* Recipe Meta Information */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
            <div className="text-center">
              <p className="text-sm text-gray-500">Prep Time</p>
              <p className="font-semibold">{recipe.prepTime} min</p>
            </div>
            <div className="text-center">
              <p className="text-sm text-gray-500">Cook Time</p>
              <p className="font-semibold">{recipe.cookTime} min</p>
            </div>
            <div className="text-center">
              <p className="text-sm text-gray-500">Servings</p>
              <p className="font-semibold">{recipe.servings}</p>
            </div>
            <div className="text-center">
              <p className="text-sm text-gray-500">Difficulty</p>
              <p className="font-semibold capitalize">{recipe.difficulty}</p>
            </div>
          </div>

          {/* Tags */}
          <div className="flex flex-wrap gap-2 mb-6">
            {recipe.tags.map((tag, index) => (
              <span
                key={index}
                className="bg-blue-100 text-blue-800 px-3 py-1 rounded-full text-sm"
              >
                {tag}
              </span>
            ))}
          </div>

          {/* Ingredients Section */}
          <div className="mb-8">
            <h2 className="text-2xl font-bold mb-4 text-gray-800">
              Ingredients
            </h2>
            <ul className="grid grid-cols-1 md:grid-cols-2 gap-2">
              {recipe.ingredients.map((ingredient, index) => (
                <li key={index} className="flex items-center space-x-2">
                  <span className="w-2 h-2 bg-orange-500 rounded-full"></span>
                  <span className="text-gray-700">
                    {ingredient.quantity} {ingredient.unit} {ingredient.name}
                  </span>
                </li>
              ))}
            </ul>
          </div>

          {/* Instructions Section */}
          <div>
            <h2 className="text-2xl font-bold mb-4 text-gray-800">
              Instructions
            </h2>
            <ol className="space-y-4">
              {recipe.instructions.map((instruction) => (
                <li key={instruction.step} className="flex space-x-4">
                  <span className="flex-shrink-0 w-8 h-8 bg-orange-500 text-white rounded-full flex items-center justify-center font-bold">
                    {instruction.step}
                  </span>
                  <p className="text-gray-700 pt-1">
                    {instruction.description}
                  </p>
                </li>
              ))}
            </ol>
          </div>

          {/* Author Info */}
          <div className="mt-8 pt-6 border-t border-gray-200">
            <p className="text-gray-600">
              <span className="font-semibold">Recipe by:</span> {recipe.author}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RecipeDetail;
